#pragma OPENCL EXTENSION cl_khr_fp64 : enable

__kernel void srad_kernel(
    const float lambda,
    const int Nr,
    const int Nc,
    const long Ne,
    __global const int* iN,
    __global const int* iS,
    __global const int* jE,
    __global const int* jW,
    __global float* d_dN,
    __global float* d_dS,
    __global float* d_dW,
    __global float* d_dE,
    __global float* d_c,
    const float q0sqr,
    __global float* d_I)
{
    int gid = get_global_id(0);
    if (gid >= Ne) return;

    int i = gid / Nc;
    int j = gid % Nc;

    float Jc = d_I[gid];

    float dN = d_I[iN[i] * Nc + j] - Jc;
    float dS = d_I[iS[i] * Nc + j] - Jc;
    float dW = d_I[i * Nc + jW[j]] - Jc;
    float dE = d_I[i * Nc + jE[j]] - Jc;

    d_dN[gid] = dN;
    d_dS[gid] = dS;
    d_dW[gid] = dW;
    d_dE[gid] = dE;

    float G2 = (dN * dN + dS * dS + dW * dW + dE * dE) / (Jc * Jc);
    float L = (dN + dS + dW + dE) / Jc;

    float num = 0.5f * G2 - (L * L) / 16.0f;
    float den = 1.0f + 0.25f * L;
    float qsqr = num / (den * den);

    den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
    float ctmp = 1.0f / (1.0f + den);

    if (ctmp < 0.0f) ctmp = 0.0f;
    else if (ctmp > 1.0f) ctmp = 1.0f;

    d_c[gid] = ctmp;
}

__kernel void srad2_kernel(
    const float lambda,
    const int Nr,
    const int Nc,
    const long Ne,
    __global const int* iN,
    __global const int* iS,
    __global const int* jE,
    __global const int* jW,
    __global const float* d_dN,
    __global const float* d_dS,
    __global const float* d_dW,
    __global const float* d_dE,
    __global const float* d_c,
    __global float* d_I)
{
    int gid = get_global_id(0);
    if (gid >= Ne) return;

    int i = gid / Nc;
    int j = gid % Nc;

    float cN = d_c[gid];
    float cS = d_c[iS[i] * Nc + j];
    float cW = d_c[gid];
    float cE = d_c[i * Nc + jE[j]];

    float D = cN * d_dN[gid] + cS * d_dS[gid] + cW * d_dW[gid] + cE * d_dE[gid];

    d_I[gid] = d_I[gid] + 0.25f * lambda * D;
}

__kernel void extract_kernel(
    const long d_Ne,
    __global float* d_I)
{
    int gid = get_global_id(0);
    if (gid >= d_Ne) return;

    d_I[gid] = exp(d_I[gid]);
}

__kernel void compress_kernel(
    const long d_Ne,
    __global float* d_I)
{
    int gid = get_global_id(0);
    if (gid >= d_Ne) return;

    d_I[gid] = log(d_I[gid]);
}

__kernel void prepare_kernel(
    const long d_Ne,
    __global const float* d_I,
    __global float* d_sums,
    __global float* d_sums2)
{
    int gid = get_global_id(0);
    if (gid >= d_Ne) return;

    float val = d_I[gid];
    d_sums[gid] = val;
    d_sums2[gid] = val * val;
}

__kernel void reduce_kernel(
    const long d_Ne,
    const int d_no,
    const int d_mul,
    __global float* d_sums,
    __global float* d_sums2)
{
    int gid = get_global_id(0);
    int nf = get_local_size(0) - (get_num_groups(0) * get_local_size(0) - d_no);
    __local float d_psum[256];
    __local float d_psum2[256];
    int tx = get_local_id(0);
    int bx = get_group_id(0);

    if (gid < d_no) {
        d_psum[tx] = d_sums[gid * d_mul];
        d_psum2[tx] = d_sums2[gid * d_mul];
    } else {
        d_psum[tx] = 0.0f;
        d_psum2[tx] = 0.0f;
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    if (nf == get_local_size(0)) {
        for (int i = 2; i <= get_local_size(0); i <<= 1) {
            if ((tx + 1) % i == 0) {
                d_psum[tx] += d_psum[tx - i / 2];
                d_psum2[tx] += d_psum2[tx - i / 2];
            }
            barrier(CLK_LOCAL_MEM_FENCE);
        }
        if (tx == get_local_size(0) - 1) {
            d_sums[bx * d_mul * get_local_size(0)] = d_psum[tx];
            d_sums2[bx * d_mul * get_local_size(0)] = d_psum2[tx];
        }
    } else {
        if (bx != get_num_groups(0) - 1) {
            for (int i = 2; i <= get_local_size(0); i <<= 1) {
                if ((tx + 1) % i == 0) {
                    d_psum[tx] += d_psum[tx - i / 2];
                    d_psum2[tx] += d_psum2[tx - i / 2];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }
            if (tx == get_local_size(0) - 1) {
                d_sums[bx * d_mul * get_local_size(0)] = d_psum[tx];
                d_sums2[bx * d_mul * get_local_size(0)] = d_psum2[tx];
            }
        } else {
            int df = 0;
            for (int i = 2; i <= nf; i <<= 1) {
                if (nf >= i) df = i;
            }
            for (int i = 2; i <= df; i <<= 1) {
                if ((tx + 1) % i == 0 && tx < df) {
                    d_psum[tx] += d_psum[tx - i / 2];
                    d_psum2[tx] += d_psum2[tx - i / 2];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }
            if (tx == df - 1) {
                for (int i = bx * get_local_size(0) + df; i < bx * get_local_size(0) + nf; i++) {
                    d_psum[tx] += d_sums[i];
                    d_psum2[tx] += d_sums2[i];
                }
                d_sums[bx * d_mul * get_local_size(0)] = d_psum[tx];
                d_sums2[bx * d_mul * get_local_size(0)] = d_psum2[tx];
            }
        }
    }
}
